import SimpleITK as sitkdef resample_to_thin_slice(        input_path: str,        output_path: str,        xyz_equal:bool = False,        x_spacing_rate:float = 1.0,        y_spacing_rate:float = 1.0,        z_spacing_rate:float = 1.0,        z_spacing:float = 1.0,        interpolator: int = None) -> None:    """    将NIfTI图像重采样到指定的薄层spacing    Args:        input_path: 输入nii文件路径        output_path: 输出nii文件路径        采样到各项同性 的薄层        interpolator: 插值器，原始图像用sitkLinear，分割标签用sitkNearestNeighbor         model:         1 : xyz_equal:   保持  x  y 方向不变  但是把z 重采样到x , y 的spacing         2 : x , y , z  按倍率处理  ，没有指定则 保持         3 :z——spacing  指定z 的重建spacing   ，x , y 不改变    """    # 1. 读取原始图像    image = sitk.ReadImage(input_path)    # 2. 获取原始图像信息    original_spacing = image.GetSpacing()    original_size = image.GetSize()    original_origin = image.GetOrigin()    original_direction = image.GetDirection()    print(f"原始图像信息:")    print(f"  大小: {original_size}")    print(f"  间距: {original_spacing[0]:.4f}, {original_spacing[1]:.4f}, {original_spacing[2]:.4f} mm")    if xyz_equal:        print("will isotropic ")        isotropic_spacing = min(original_spacing[0], original_spacing[1], original_spacing[2])        print(f"will isotropic at {isotropic_spacing} mm    ")        target_spacing = (isotropic_spacing, isotropic_spacing, isotropic_spacing)    elif (x_spacing_rate != 1.0)  or (y_spacing_rate != 1.0)  or (z_spacing_rate != 1.0):        target_spacing = (original_spacing[0]*x_spacing_rate,original_spacing[1]*y_spacing_rate,original_spacing[2]*z_spacing_rate)    elif z_spacing != 0:        target_spacing = (original_spacing[0],original_spacing[0],z_spacing)    # 3. 计算新的图像大小    # 公式: 新大小 = 原始大小 * (原始间距 / 目标间距)    new_size = [        int(round(original_size[0] * (original_spacing[0] / target_spacing[0]))),        int(round(original_size[1] * (original_spacing[1] / target_spacing[1]))),        int(round(original_size[2] * (original_spacing[2] / target_spacing[2])))    ]    print(f"\n重采样后信息:")    print(f"  大小: {new_size}")    print(f"  间距: {target_spacing[0]:.4f}, {target_spacing[1]:.4f}, {target_spacing[2]:.4f} mm")    print(f"  层数增加: {original_size[2]} → {new_size[2]} (×{new_size[2] / original_size[2]:.1f})")    # 4. 创建重采样器m 需要知道、spacing \ 尺寸 \ 原点 \ 方向 \ 插值方法    resampler = sitk.ResampleImageFilter()    resampler.SetOutputSpacing(target_spacing)    resampler.SetSize(new_size)    resampler.SetOutputOrigin(original_origin)    resampler.SetOutputDirection(original_direction)    resampler.SetInterpolator(interpolator)    # 5. 执行重采样    resampled_image = resampler.Execute(image)    # 6. 保存结果    sitk.WriteImage(resampled_image, output_path)    print(f"\n重采样完成，已保存至: {output_path}")# 使用示例if __name__ == "__main__":    import  os    input_floder = r"/home/liangshubo/Project/CTSR/dataset/rawdata/Elite_dataset/all/"    output_floder = r"/home/liangshubo/Project/CTSR/dataset/rawdata/Elite_dataset/all_isotropic"    if not os.path.exists(output_floder):        os.makedirs(output_floder)    namelist = os.listdir(input_floder)    i=1    for name in namelist:        input_path = os.path.join(input_floder, name)        output_path = os.path.join(output_floder, name)        # 冠状面 ：[x , y ]   矢状面  ：[ y ,z ]   冠状面  ：[  x,z ]  如果一起动 会导致图像数量改变        resample_to_thin_slice(            input_path=input_path,            output_path=output_path,            xyz_equal= True,            x_spacing_rate = 1,  # sizedown  2x ： 2 ; sizedown 4x ：4  ；sizeup 2x :0.5  ;sizeup4x :0.25            y_spacing_rate=1,            z_spacing_rate=1,            z_spacing = 0,            interpolator=sitk.sitkBSpline3 #sitk.sitkLanczosWindowedSinc#sitk.sitkBSpline        )        print(f"{i}/{len(namelist)}")        i+=1    # 选项2: 重采样到完全各向同性（和xy轴一致0.68mm）    # resample_to_thin_slice(    #     input_path="input.nii.gz",    #     output_path="output_isotropic_0.68mm.nii.gz",    #     ta